const rows = $input.all();
const conversations = rows.map((r) => {
  const labels = Array.isArray(r.json.labels) ? r.json.labels : typeof r.json.labels === 'string' ? JSON.parse(r.json.labels || '[]') : [];
  return {
    id: r.json.id,
    customerUserId: r.json.customer_user_id,
    customerExternalId: r.json.external_user_id,
    customerName: r.json.display_name || r.json.external_user_id || r.json.id,
    customerAvatar: r.json.picture_url || null,
    customerEmail: r.json.email || '',
    customerPhone: r.json.phone || '',
    channel: r.json.channel,
    status: r.json.status,
    lastMessage: r.json.last_message || '',
    lastMessageAt: r.json.last_message_at,
    unreadCount: parseInt(r.json.unread_count) || 0,
    labels,
    messages: [],
    createdAt: r.json.created_at,
    updatedAt: r.json.updated_at,
  };
});
return [{ json: { conversations, total: conversations.length } }];

const input = $input.first().json;
const body   = input.body   || {};
const conversationId = body.conversationId || '';
const tags = Array.isArray(body.tags) ? body.tags : [];
const cleaned = tags
  .map((tag) => ({
    name:  String(tag.name  || '').trim(),
    color: String(tag.color || '#2563eb').trim(),
  }))
  .filter((tag) => tag.name.length > 0);
return [{ json: { conversationId, tags: cleaned } }];

const row = $input.first()?.json || {};
const labels = Array.isArray(row.labels)
  ? row.labels
  : typeof row.labels === 'string'
    ? JSON.parse(row.labels || '[]')
    : [];
return [{
  json: {
    conversationId: row.conversation_id || $('Code: Parse Tags').first().json.conversationId,
    labels,
  }
}];

const r        = $input.first().json;
const total    = parseInt(r.total_conversations) || 0;
const human    = parseInt(r.human_required)      || 0;
const bot      = parseInt(r.bot_handled)         || 0;
const today    = parseInt(r.today_messages)      || 0;
const line     = parseInt(r.line_count)          || 0;
const resolved = parseInt(r.resolved_count)      || 0;
return [{ json: {
  totalConversations: total,
  botHandled:         bot,
  humanRequired:      human,
  resolved,
  channelStats: { line, facebook: 0, instagram: 0, tiktok: 0 },
  todayMessages: today,
  responseRate:  0,
} }];

const input = $input.first().json;
const body = input.body || {};
return [{ json: {
  name:  String(body.name  || '').trim(),
  color: String(body.color || '#2563eb').trim(),
  scope: String(body.scope || 'global').trim(),
} }];

parameters.query:
CREATE UNIQUE INDEX IF NOT EXISTS idx_tags_name_scope ON tags (name, scope);
INSERT INTO tags (name, color, scope)
VALUES ('{{ $json.name }}', '{{ $json.color }}', '{{ $json.scope }}')
ON CONFLICT (name, scope) DO UPDATE SET color = EXCLUDED.color
RETURNING id::TEXT, name, color, scope;

